    if (
        test_input.shape[1] != self.input_dimension
        or test_input.shape[2] != self.task_count
    ):
        raise ValueError(
            "The input tensor should be of size N x D x T, where D is the input dimension and T is the number of tasks"
        )

    # first, generate the latent sample
