        0
    ]  # there will only be one, but the base class has this as a list

    latent_samples = torch.zeros(
        sample_count, test_input.shape[0], self.latent_sample_count
    )

    # there are R latent sample functions; where R is the number of coefficients
    # so white_noise_sample should be of size N x n x T x R
    # where:
    # N is the number of different function samples;
    # n is the number of input values for each sample
    # T is the number of tasks - Isotopic samples will
    # be repeated along the T dimension.
    # and R is the number of latent sample functions
    white_noise_sample = D.Normal(0, 1).sample(
        (sample_count, test_input.shape[0], self.latent_sample_count)
    )

    # first, build the latent samples
    for task in range(self.task_count):  # for each of the tasks
        for n in range(
            sample_count
        ):  # for each of the function samples to generate
            for i in range(
                self.latent_sample_count
            ):  # for each of the latent sample functions
                kernel_matrix = kernel(
                    test_input[:, :, task], test_input[:, :, task]
                ) + self.jitter * torch.eye(test_input.shape[0])

